/* Кириличний шрифт (DejaVu Sans, засабсечено: латиниця+кирилиця+символи).
   1) Реєструється в jsPDF як шрифт "Sheet" (normal/bold) — для рендера PDF.
   2) Реєструється як CSS FontFace "SheetMeasure" — щоб через canvas measureText
      точно міряти ширину тексту (jsPDF.getTextWidth не працює для вбудованих TTF).
   window.DndFontsReady — проміс, що резолвиться, коли шрифти для вимірювання
   завантажені (finish() чекає на нього перед генерацією). */
(function(){
  if(!window.jspdf||!window.jspdf.jsPDF){console.error("jsPDF не завантажено перед fonts.js");return;}
  var REG="";
  var BOLD="";
  // --- jsPDF ---
  window.jspdf.jsPDF.API.events.push(["addFonts", function(){
    this.addFileToVFS("DejaVuSans.ttf", REG);
    this.addFont("DejaVuSans.ttf", "Sheet", "normal");
    this.addFileToVFS("DejaVuSans-Bold.ttf", BOLD);
    this.addFont("DejaVuSans-Bold.ttf", "Sheet", "bold");
  }]);
  // --- CSS FontFace (для вимірювання ширини) ---
  window.DndFontsReady = (function(){
    try{
      if(typeof FontFace==="undefined"||!document.fonts) return Promise.resolve(false);
      var ffR=new FontFace("SheetMeasure","url(data:font/ttf;base64,"+REG+")",{weight:"400"});
      var ffB=new FontFace("SheetMeasure","url(data:font/ttf;base64,"+BOLD+")",{weight:"700"});
      return Promise.all([ffR.load(),ffB.load()]).then(function(fs){
        document.fonts.add(fs[0]); document.fonts.add(fs[1]); return true;
      }).catch(function(){ return false; });
    }catch(e){ return Promise.resolve(false); }
  })();
})();
